        if hasattr(r, "to_dict") and callable(getattr(r, "to_dict")):
            base.update(r.to_dict())
        else:
            # Fallback: extract commonly expected attributes
            for attr in ("id", "score", "metadata", "text", "content"):
                if hasattr(r, attr):
                    base[attr] = getattr(r, attr)

        # Flatten metadata (if present) into top level for filtering convenience
