from typing import List, Dict, Any
from leann.api import PassageManager
from pathlib import Path
from collections import Counter, defaultdict


def _load_passage_manager(index_path: str) -> PassageManager:
    """
    Internal helper to load a PassageManager and normalize / validate path.
    Raises FileNotFoundError if the index path (or its metadata) does not exist.
    """
    path = Path(index_path)

    # Basic existence check – if the directory or file isn't there, bail out
    if not path.exists():
        raise FileNotFoundError(f"Index path not found: {index_path}")

    # Let PassageManager perform its own loading/validation.
    # If LEANN uses a specific metadata file (e.g. index.json, meta.json),
    # it will fail here if that file is missing.
    try:
        pm = PassageManager(index_path=str(path))
    except FileNotFoundError:
        # Re-raise as required by the spec
        raise
    except Exception as exc:
        # Wrap other loading errors as FileNotFoundError to match the contract
        raise FileNotFoundError(
            f"Index metadata file is not found or cannot be loaded for: {index_path}"
        ) from exc

    return pm


def get_index_statistics(index_path: str) -> Dict[str, Any]:
    """Get comprehensive statistics about a LEANN index.

    Args:
        index_path: Path to the LEANN index file

    Returns:
        Dictionary containing:
        {
            "total_passages": total number of passages,
            "metadata_fields": list of unique metadata field names,
            "field_value_counts": dictionary of field value counts
        }

    Raises:
        FileNotFoundError: If index metadata file is not found
    """
    pm = _load_passage_manager(index_path)

    total_passages = 0
    metadata_fields = set()
    field_value_counts: Dict[str, Counter] = defaultdict(Counter)

    # Assuming PassageManager is iterable over passages or has an appropriate API.
    # Each passage is expected to have a "metadata" dict-like attribute.
    for passage in pm:
        total_passages += 1
        metadata = getattr(passage, "metadata", {}) or {}

        for key, value in metadata.items():
            metadata_fields.add(key)
            # Convert non-hashable or complex values to string for counting
            try:
                field_value_counts[key][value] += 1
            except TypeError:
                field_value_counts[key][str(value)] += 1

    # Convert Counters to regular dicts for JSON‑friendly output
    field_value_counts_serializable: Dict[str, Dict[Any, int]] = {
        field: dict(counter) for field, counter in field_value_counts.items()
    }

    return {
        "total_passages": total_passages,
        "metadata_fields": sorted(metadata_fields),
        "field_value_counts": field_value_counts_serializable,
    }


def analyze_index_coverage(index_path: str, required_fields: List[str]) -> Dict[str, Any]:
    """Analyze how well an index covers required metadata fields.

    Args:
        index_path: Path to the LEANN index file
        required_fields: List of metadata field names that should be present

    Returns:
        Dictionary containing:
        {
            "coverage_percentage": percentage of passages that have all required fields,
            "field_coverage": dictionary mapping field name to coverage percentage,
            "missing_fields": list of required fields not found in any passage
        }

    Raises:
        FileNotFoundError: If index metadata file is not found
    """
    pm = _load_passage_manager(index_path)

    total_passages = 0
    field_present_counts: Dict[str, int] = {field: 0 for field in required_fields}
    passages_with_all_required = 0

    # Track which fields appear in at least one passage
    fields_seen_at_all = {field: False for field in required_fields}

    for passage in pm:
        total_passages += 1
        metadata = getattr(passage, "metadata", {}) or {}

        has_all = True
        for field in required_fields:
            if field in metadata and metadata[field] is not None:
                field_present_counts[field] += 1
                fields_seen_at_all[field] = True
            else:
                has_all = False

        if has_all and required_fields:
            passages_with_all_required += 1

    if total_passages == 0:
        # Avoid division by zero; no passages means 0% coverage everywhere.
        coverage_percentage = 0.0
        field_coverage = {field: 0.0 for field in required_fields}
    else:
        coverage_percentage = (
            passages_with_all_required / total_passages * 100.0
            if required_fields
            else 100.0
        )
        field_coverage = {
            field: (field_present_counts[field] / total_passages * 100.0)
            for field in required_fields
        }

    missing_fields = [field for field, seen in fields_seen_at_all.items() if not seen]

    return {
        "coverage_percentage": coverage_percentage,
        "field_coverage": field_coverage,
        "missing_fields": missing_fields,
    }
